info.narration:
      [
      {$0 ถูกวางบนเบาะนุ่มๆ ราวกับจัดแสดง},
      {ถ้าคุณเห็นบางสิ่งที่คล้ายฟันอยู่ด้านในของ $0 มันก็เป็นแค่ภาพลวงตา},
      {ใครก็ตามที่มอง $0 จะรู้สึกอยากลองสวมใส่มันอย่างไม่อาจต้านทานได้},
      {เด็กสาวร้องขอทั้งน้ำตา “คุณลุงคะ ได้โปรดตัดเท้าของหนูออกเถอะ…”}
      ]

      [
      {ปล่อย $0 ไว้บนเบาะที่เก่าแล้ว #0 เริ่มต้นการทำงาน},
      {ราวกับว่าเพิ่งมีคนถอดมันออก $0 กำลังนอนอยู่บนพื้น},
      {เดินผ่าน $0 ที่จัดวางไว้อย่างเรียบร้อย #0 ก็ยังคงทำงานต่อไป}
      ]

      [
      {หนังเคลือบสีแดงของ $0 เป็นประกายในแสงไฟ},
      {สายรัดข้อเท้าบน $0 ยังคงดูสง่างามแม้ว่าจะเก่าแล้วก็ตาม},
      {ราวกับแสดงให้เห็นถึงประวัติศาสตร์อันยาวนาน ส้นรองเท้าของ $0 ก็สึกหรอ},
      {สภาพที่ไร้ที่ติของหนังของ $0 ดูเหมือนจะผิดปกติ}
      ]

      [
      {#0 แอบเหลือบมอง $0 ขณะที่พวกเขากำลังทำงาน},
      {#0 เอาแต่มอง $0},
      {#0 ที่กำลังมีปัญหาในการจดจ่อ ก็หยุดทำงานและหันไปมอง $0},
      {พยายามที่จะต้านทานการมอง $0 อีกครั้ง #0 มองไปในทิศทางตรงกันข้าม พยายามที่จะกลับไปทำงานที่ทำอยู่}
      ]

      [
      {$0 ไม่ใช่สิ่งมีชีวิตอย่างชัดเจน แต่มันกลับปล่อยบรรยากาศที่น่าสังเวชออกมา},
      {$0 อาจไม่ใช่สิ่งมีชีวิตที่หายใจได้ แต่บรรยากาศที่โดดเด่นของมันทำให้ผู้ที่อยู่ใกล้เคียงนึกถึงอดีตที่เต็มไปด้วยเลือด},
      {สีเลือดของ $0 ดูคุ้นตาอย่างประหลาด},
      {$0 นอนนิ่งอยู่}
      ]

      [
      {#0 ไม่สนใจคำสั่งของพวกเขาและเหลือบมอง $0 อย่างต่อเนื่อง ตอนนี้พวกเขากำลังเอื้อมมือไปหยิบรองเท้า}
      ]

      [
      {#0 ถอดรองเท้าของตัวเองออกและเริ่มสวม $0}
      ]

      [
      {ดวงตาของ #0 ดูแตกต่างออกไป รูม่านตาของพวกเขาขยายและไม่โฟกัส}
      ]

      [
      {#0 พอใจกับการสวมใส่ $0 และเพลิดเพลินกับเสียงส้นรองเท้าที่เคาะ}
      ]

      [
      {#0 เดินไปตามทางเดินพร้อมกับขวานในมือ},
      {#0 ใช้อาวุธของพวกเขาต่อสู้กับ #1 ที่พยายามจะหยุดพวกเขา},
      {#1 ถูกอาวุธของ #0 ฟาดเข้าที่หัวและเสียชีวิตด้วยภาวะเลือดออกในสมอง}
      ]

observe.desc:
      [
      {รองเท้าสตรีสีแดงคู่หนึ่งที่ดูหรูหรา การออกแบบเป็นแบบโบราณ แต่ไม่สามารถบอกได้ว่ามันถูกสร้างขึ้นที่ไหนและอย่างไร}
      ]

      [
      {มันทำให้จิตใจอยากลองสวมใส่ การเปลี่ยนแปลงที่เกิดขึ้นจากการสวมใส่ Abnormality นี้จะปรากฏให้เห็นในดวงตาของผู้สวมใส่ก่อน}
      ]

      [
      {การเปลี่ยนแปลงที่สังเกตได้ต่อไปคือผู้สวมใส่จะไม่ยอมถอดรองเท้า พวกเขาจะกระทำตามความปรารถนาทั้งหมดที่พวกเขาอาจจะกดดันไว้โดยไม่รู้ตัว หากมีคนพยายามขัดขวางไม่ให้พวกเขากระทำตามความปรารถนาหรือพยายามถอดรองเท้า รองเท้าจะควบคุมผู้สวมใส่ ซึ่งบางครั้งนำไปสู่การฆาตกรรม}
      ]

      [
      {ไม่ทราบว่าเจตจำนงของผู้สวมใส่มาร่วมในกระบวนการนี้หรือไม่ แต่เมื่อพิจารณาจากการเพิ่มขึ้นอย่างรวดเร็วของความปรารถนาและความก้าวร้าวแล้ว สัญชาตญาณดั้งเดิมของผู้สวมใส่ดูเหมือนจะยังคงอยู่}
      ]

      [
      {<ข้อความที่ตัดตอนจากบันทึกการให้คำปรึกษา>

      “<ข้อมูลถูกลบ> เป็นคนดี อืม พวกเขาก็ค่อนข้างจะเป็นคนดังด้วย พวกเขาบอกเราเสมอว่างานของเราเป็นสิ่งที่น่าภาคภูมิใจ พวกเขารู้วิธีจัดการกับ Abnormality ทุกประเภท แต่มันเป็นความผิดพลาดที่ใหญ่ที่สุดของเราที่ปล่อยให้พวกเขาเข้าไปในห้องกักกันนั้น เราไม่เคยคิดเลยว่ารองเท้าจะทำอันตรายได้ ที่จุดหนึ่ง <ข้อมูลถูกลบ> กำลังสวมรองเท้า ยิ้มกว้างถึงใบหู อืม มันค่อนข้างแปลกน่ะ นั่นไม่ใช่รอยยิ้ม มันคือ... (ถูกละไว้) เลือดสาดไปทั่วบริเวณ เสียงส้นรองเท้าดังก้องไปทั่วทางเดิน ฉันหลับตาลงและแกล้งตาย ฉันเห็นหัวของเพื่อนร่วมงานคนหนึ่งกลิ้งไปมาบนพื้น รองเท้าหยุดอยู่ตรงหน้าฉันและยืนนิ่งอยู่นานมาก ในที่สุดพวกมันก็เดินผ่านฉันไป และนั่นคือตอนที่ฉันหมดสติ (ถูกละไว้) ฉันได้ยินมาว่าพวกเขาถอดรองเท้าไม่ได้และต้องตัดขาออก ไม่มีใครได้เห็น <ข้อมูลถูกลบ> อีกเลยหลังจากนั้น แต่ผู้ที่อยู่ที่นี่มานานพอจะจำเหตุการณ์นี้ได้”}
      ]

      [
      {<ข้อความที่ตัดตอนจากบันทึกการวิจัย>

      <i>เราได้รับรายงานว่าพนักงาน <ข้อมูลถูกลบ> ถูกล่อลวงโดยรองเท้าและกำลังเดินไปตามทางเดิน เราสั่งให้พนักงาน F3054 ปราบปรามเธอทันที เธอเป็นพนักงานอาวุโสที่มีประสบการณ์มากมายในการปราบปราม ดังนั้นเราจึงคาดหวังว่าเธอจะปราบพนักงานหญิงได้โดยไม่มีปัญหา แต่เธอกลับไม่กลับมา และเมื่อคนอื่นพบเธอ พนักงาน F4002 ก็หมดสติโดยที่ข้อเท้าทั้งสองข้างถูกตัดออก ในขณะที่พนักงาน F3054 กำลังพยายามถอดรองเท้าออกจากเท้าที่ถูกตัดออกอย่างบ้าคลั่ง</i>}
      ]
